// ============================================================
// SHOP DATA — loaded from config.js, enriched with internal styles
// ============================================================
const IMG_CLASS_MAP = {
  sarees        : 'img-placeholder-saree',
  dresses       : 'img-placeholder-dress',
  fabrics       : 'img-placeholder-fabric',
  linings       : 'img-placeholder-lining',
  cordsets      : 'img-placeholder-cord',
  dupattas      : 'img-placeholder-dupatta',
  'lace-latkans': 'img-placeholder-lace',
};

// Merge config with internal styling (imgClass) so config stays clean
const SHOP_DATA = (function () {
  const data = { ...SHOP_CONFIG };
  data.categories = data.categories.map(cat => ({
    ...cat,
    imgClass: IMG_CLASS_MAP[cat.id] || 'img-placeholder',
  }));
  return data;
})();

/** Resolve path to a page — accounts for index.html at root vs src/ pages */
function pagePath(filename) {
  const inSrc = window.location.pathname.includes('/src/');
  if (filename === 'index.html') return inSrc ? '../index.html' : 'index.html';
  return inSrc ? filename : 'src/' + filename;
}

// ============================================================
// UTILITY
// ============================================================

/** Build carousel HTML for a category's images (auto-rotates) */
function buildCarouselHTML(cat, height = '224px') {
  // Auto-generate image paths from coverCount: cover-1.jpg, cover-2.jpg, ...
  const count = cat.coverCount || 0;
  const prefix = window.location.pathname.includes('/src/') ? '../' : '';
  const images = [];
  for (let i = 1; i <= count; i++) {
    images.push(`${prefix}assets/images/${cat.id}/cover-${i}.jpg`);
  }

  // No images — show gradient placeholder
  if (!images.length) {
    return `<div class="img-placeholder ${cat.imgClass}" style="height:${height};width:100%;">
      <div style="text-align:center;padding:16px;">
        <div style="font-size:2.5rem;margin-bottom:6px;">${cat.icon}</div>
        <span style="color:rgba(255,255,255,0.55);font-size:11px;text-transform:uppercase;letter-spacing:1.5px;">Add Photo</span>
      </div>
    </div>`;
  }

  // Single image — no carousel needed
  if (images.length === 1) {
    return `<img src="${images[0]}" alt="${cat.name}" class="w-full object-cover" style="height:${height};" loading="lazy">`;
  }

  // Multiple images — auto-sliding carousel
  const uid = 'carousel-' + cat.id;
  return `<div class="category-carousel" id="${uid}" style="position:relative;height:${height};overflow:hidden;">
    ${images.map((src, idx) => `
      <img src="${src}" alt="${cat.name}" class="carousel-slide w-full object-cover" 
           style="height:${height};position:absolute;inset:0;opacity:${idx === 0 ? 1 : 0};transition:opacity 0.8s ease;"
           loading="lazy">
    `).join('')}
    <div style="position:absolute;bottom:8px;left:50%;transform:translateX(-50%);display:flex;gap:5px;">
      ${images.map((_, idx) => `<span class="carousel-dot" style="width:7px;height:7px;border-radius:50%;background:${idx === 0 ? '#fff' : 'rgba(255,255,255,0.5)'};transition:background 0.3s;"></span>`).join('')}
    </div>
  </div>`;
}

/** Build a wa.me link with pre-filled text */
function buildWhatsAppLink(message) {
  const n = SHOP_DATA.whatsapp;
  return `https://wa.me/${n}?text=${encodeURIComponent(message)}`;
}

