// ============================================================
// NAVBAR
// ============================================================
function initNavbar() {
  const hamburger  = document.getElementById('hamburger');
  const mobileMenu = document.getElementById('mobile-menu');
  const navbar     = document.getElementById('navbar');

  // Toggle mobile menu
  if (hamburger && mobileMenu) {
    hamburger.addEventListener('click', () => {
      const isOpen = mobileMenu.classList.toggle('open');
      hamburger.setAttribute('aria-expanded', String(isOpen));
    });
    // Close on any link click
    mobileMenu.querySelectorAll('a').forEach(link => {
      link.addEventListener('click', () => {
        mobileMenu.classList.remove('open');
        hamburger.setAttribute('aria-expanded', 'false');
      });
    });
  }

  // Add shadow when scrolled
  if (navbar) {
    const toggleShadow = () =>
      navbar.classList.toggle('shadow-md', window.scrollY > 20);
    window.addEventListener('scroll', toggleShadow, { passive: true });
    toggleShadow();
  }

  // Highlight active nav link
  const page = window.location.pathname.split('/').pop() || 'index.html';
  document.querySelectorAll('.nav-link').forEach(link => {
    const href = (link.getAttribute('href') || '').split('/').pop();
    if (href === page || (page === '' && href === 'index.html')) {
      link.classList.add('active');
    }
  });
}

// ============================================================
// SCROLL ANIMATIONS  (Intersection Observer)
// ============================================================
function initScrollAnimations() {
  const els = document.querySelectorAll('.fade-up, .fade-in, .slide-left, .slide-right');
  if (!els.length) return;

  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible');
        observer.unobserve(entry.target); // one-shot
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  els.forEach(el => observer.observe(el));
}

// ============================================================
// BACK TO TOP
// ============================================================
function initBackToTop() {
  const btn = document.getElementById('back-to-top');
  if (!btn) return;
  window.addEventListener('scroll', () =>
    btn.classList.toggle('visible', window.scrollY > 400), { passive: true });
  btn.addEventListener('click', () =>
    window.scrollTo({ top: 0, behavior: 'smooth' }));
}

// ============================================================
// CONTACT FORM → WHATSAPP
// ============================================================
function initContactForm() {
  const form = document.getElementById('contact-form');
  if (!form) return;

  form.addEventListener('submit', function (e) {
    e.preventDefault();

    const name     = (form.querySelector('[name="name"]')?.value     || '').trim();
    const phone    = (form.querySelector('[name="phone"]')?.value    || '').trim();
    const category = (form.querySelector('[name="category"]')?.value || '').trim();
    const message  = (form.querySelector('[name="message"]')?.value  || '').trim();

    if (!name || !phone) {
      alert('Please provide your name and phone number.');
      return;
    }

    // Basic phone validation
    if (!/^[\d\s\+\-\(\)]{7,15}$/.test(phone)) {
      alert('Please enter a valid phone number.');
      return;
    }

    const waMsg =
      `Hello! I found you on your website 🙏\n\n` +
      `*Name:* ${name}\n` +
      `*Phone:* ${phone}\n` +
      `*Category:* ${category || 'Not specified'}\n` +
      `*Message:* ${message || "I'd like more information."}\n\n` +
      `— Sent from matchndesignbyminal.com`;

    window.open(buildWhatsAppLink(waMsg), '_blank', 'noopener,noreferrer');
  });
}

// ============================================================
// LAZY LOAD IMAGES
// ============================================================
function initLazyLoad() {
  const imgs = document.querySelectorAll('img[data-src]');
  if (!imgs.length) return;

  if ('IntersectionObserver' in window) {
    const io = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const img = entry.target;
          img.src = img.dataset.src;
          img.removeAttribute('data-src');
          io.unobserve(img);
        }
      });
    });
    imgs.forEach(img => io.observe(img));
  } else {
    // Fallback
    imgs.forEach(img => { img.src = img.dataset.src; });
  }
}

// ============================================================
// RENDER — STORE INFO
// Populates all [data-*] elements from SHOP_DATA
// ============================================================
function renderStoreInfo() {
  const defaultMsg = `Hello! I'd like to know more about Match & Design.`;

  // WhatsApp links
  document.querySelectorAll('[data-whatsapp]').forEach(el => {
    el.href = buildWhatsAppLink(defaultMsg);
  });

  // Phone links
  document.querySelectorAll('[data-phone]').forEach(el => {
    el.href = `tel:${SHOP_DATA.phone}`;
    // Only replace text content if the element has no child elements (buttons have SVG icons)
    if (!el.children.length) {
      el.textContent = SHOP_DATA.phone;
    }
  });

  // Social links
  document.querySelectorAll('[data-instagram]').forEach(el => {
    el.href = SHOP_DATA.social.instagram;
  });
  document.querySelectorAll('[data-facebook]').forEach(el => {
    el.href = SHOP_DATA.social.facebook;
  });

  // Address
  document.querySelectorAll('[data-shop-address]').forEach(el => {
    el.textContent = SHOP_DATA.address;
  });

  // Timings
  const timingsEl = document.getElementById('store-timings');
  if (timingsEl) {
    timingsEl.innerHTML =
      `<p>${SHOP_DATA.timings.weekdays}</p><p>${SHOP_DATA.timings.sunday}</p>`;
  }

  // Map embed — only use proper embed URLs
  const mapEl = document.getElementById('map-container');
  if (mapEl && SHOP_DATA.mapEmbedUrl && (SHOP_DATA.mapEmbedUrl.includes('embed') || SHOP_DATA.mapEmbedUrl.includes('maps.google'))) {
    mapEl.innerHTML = `
      <iframe src="${SHOP_DATA.mapEmbedUrl}"
              width="100%" height="320" style="border:0;" allowfullscreen
              loading="lazy" referrerpolicy="no-referrer-when-downgrade"
              title="Match & Design — Store Location"></iframe>`;
  }

  // Stats
  const statMap = {
    'stat-years'     : SHOP_DATA.yearsOfService,
    'stat-customers' : SHOP_DATA.happyCustomers,
    'stat-collections': SHOP_DATA.collections,
  };
  Object.entries(statMap).forEach(([id, val]) => {
    const el = document.getElementById(id);
    if (el) el.textContent = val;
  });

  // Footer year
  const yearEl = document.getElementById('footer-year');
  if (yearEl) yearEl.textContent = new Date().getFullYear();
}

// ============================================================
// RENDER — CATEGORY CARDS (index.html & products.html)
// ============================================================
function renderCategories() {
  const grid = document.getElementById('categories-grid');
  if (!grid) return;

  grid.innerHTML = SHOP_DATA.categories.map((cat, i) => `
    <div class="category-card fade-up stagger-${Math.min(i + 1, 6)}" style="display:flex;flex-direction:column;">
      ${buildCarouselHTML(cat, '224px')}
      <div style="padding:20px;display:flex;flex-direction:column;flex:1;">
        <h3 style="font-family:'Playfair Display',serif;font-size:1.05rem;font-weight:600;color:#2B6B4E;margin-bottom:8px;">${cat.name}</h3>
        <p style="font-size:0.82rem;color:#4A6B5A;line-height:1.6;margin-bottom:14px;">${cat.description}</p>
        <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-top:auto;">
          <span class="price-tag" style="font-size:0.85rem;">${cat.priceRange}</span>
          <a href="${pagePath('products.html')}#${cat.id}" class="btn-primary"
             style="font-size:0.75rem;padding:7px 14px;border-radius:2px;white-space:nowrap;">
            View Collection
          </a>
        </div>
      </div>
    </div>
  `).join('');

  initLazyLoad();
}

