// ============================================================
// RENDER — PRODUCTS PAGE (products.html)
// Shows all categories with descriptions and price ranges
// ============================================================
function renderProductsPage() {
  const filtersEl = document.getElementById('product-filters');
  const gridEl    = document.getElementById('products-grid');
  const countEl   = document.getElementById('product-count');
  if (!gridEl) return;

  // Hide the filter tabs — not needed for simple category view
  if (filtersEl) filtersEl.style.display = 'none';

  // Update count
  if (countEl) countEl.textContent = SHOP_DATA.categories.length;

  // Render all categories as cards
  gridEl.innerHTML = SHOP_DATA.categories.map((cat, i) => `
    <div class="category-card fade-up stagger-${Math.min((i % 6) + 1, 6)}" style="display:flex;flex-direction:column;">
      ${buildCarouselHTML(cat, '200px')}
      <div style="padding:20px;display:flex;flex-direction:column;flex:1;">
        <h3 style="font-family:'Playfair Display',serif;font-size:1.1rem;font-weight:600;color:#1F2E28;margin-bottom:8px;">${cat.name}</h3>
        <p style="font-size:0.82rem;color:#4A6B5A;line-height:1.6;margin-bottom:14px;">${cat.description}</p>
        <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-top:auto;">
          <span class="price-tag" style="font-size:0.85rem;">${cat.priceRange}</span>
          <button onclick="inquireProduct('${cat.name.replace(/'/g, "\\'")}')"
                  class="btn-primary"
                  style="font-size:0.75rem;padding:8px 16px;border-radius:2px;white-space:nowrap;">
            Inquire Now
          </button>
        </div>
      </div>
    </div>
  `).join('');

  // Run animations and lazy load
  initScrollAnimations();
  initLazyLoad();
  renderStoreInfo();
}

// ============================================================
// POPULATE — CONTACT FORM CATEGORY DROPDOWN
// ============================================================
function populateCategoryDropdown() {
  const sel = document.getElementById('form-category');
  if (!sel) return;
  SHOP_DATA.categories.forEach(cat => {
    const opt = document.createElement('option');
    opt.value       = cat.id;
    opt.textContent = cat.name;
    sel.appendChild(opt);
  });
}

// ============================================================
// PRODUCT INQUIRY (called from inline onclick)
// ============================================================
function inquireProduct(title) {
  const msg =
    `Hello! I'm interested in *${title}* from Match & Design.\n` +
    `Could you please share details, availability, and pricing? 🙏`;
  window.open(buildWhatsAppLink(msg), '_blank', 'noopener,noreferrer');
}

// ============================================================
// CAROUSEL — auto-rotate category images
// ============================================================
function initCarousels() {
  document.querySelectorAll('.category-carousel').forEach(carousel => {
    const slides = carousel.querySelectorAll('.carousel-slide');
    const dots = carousel.querySelectorAll('.carousel-dot');
    if (slides.length <= 1) return;

    let current = 0;
    const total = slides.length;

    function showSlide(idx) {
      slides.forEach((s, i) => { s.style.opacity = i === idx ? '1' : '0'; });
      dots.forEach((d, i) => { d.style.background = i === idx ? '#fff' : 'rgba(255,255,255,0.5)'; });
    }

    setInterval(() => {
      current = (current + 1) % total;
      showSlide(current);
    }, 3500);
  });
}

// ============================================================
// INIT — runs on every page
// ============================================================
document.addEventListener('DOMContentLoaded', () => {
  initNavbar();
  renderStoreInfo();
  renderCategories();
  renderFeatured();
  renderTestimonials();
  renderFeatures();
  renderProductsPage();
  populateCategoryDropdown();

  // Delay animations slightly so layout is settled
  requestAnimationFrame(() => {
    initScrollAnimations();
    initBackToTop();
    initContactForm();
    initLazyLoad();
    initCarousels();
  });
});
